options.css:
body {
  margin: 0;
  padding: 0;
  font-family: Arial, sans-serif;
  background-color: #f0f0f0;
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
}

.adapted-container {
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(to right, #007b9a, #004f6b);
  padding: 17px;
  border-radius: 15px;
  width: 100%;
  height: 80%;
  box-sizing: border-box;
}


.adapted-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  width: 100%;
}

.adapted-value-container {
  display: flex;
    align-items: center;
  flex-direction: column;
  align-items: center; /* Alinha o conteúdo à direita */
  justify-content: center;
  width: 100%;
  position: relative; /* Necessário para o alinhamento vertical */
}



.adapted-name {
  color: #FFFFFF;
  font-weight: bold;
    align-items: center;
  font-size: 25px;
  margin-top: 5px; /* Espaçamento entre o valor e o texto */
  animation: text-glow 1.5s ease-in-out infinite alternate; /* Adiciona animação pulsando indo e voltando */
}

.adapted-value {
  color: #FFFFFF;
  font-weight: bold;
    align-items: center;
  font-size: 25px;
  margin-top: 5px; /* Espaçamento entre o valor e o texto */
  animation: text-glow 1.5s ease-in-out infinite alternate; /* Adiciona animação pulsando indo e voltando */
}

@keyframes text-glow {
  from {
    text-shadow: 0 0 5px #56d5dc, 0 0 10px #56d5dc, 0 0 20px #56d5dc, 0 0 30px #56d5dc;
  }
  to {
    text-shadow: 0 0 10px #56d5dc, 0 0 20px #56d5dc, 0 0 30px #56d5dc, 0 0 40px #56d5dc;
  }
}

/* Consultas de mídia para dispositivos móveis */
@media (max-width: 600px) {
  .adapted-container {
    flex-direction: column;
    align-items: flex-start;
    width: 100%;
  }

  .adapted-image {
    width: 30px;
    height: 35px;
    margin-right: 0;
    margin-bottom: 10px;
  }

options.onInit:
// Sets the text from customProperties
const htmlgraphicsText = htmlNode.getElementById('htmlgraphics-text');

if (htmlgraphicsText) {
  htmlgraphicsText.textContent = customProperties.text;

  // Change the text color based on the theme
  if (theme.isDark) {
    htmlgraphicsText.style.color = 'green';
  } else {
    htmlgraphicsText.style.color = 'red';
  }
}

options.onRender:
// Sets the value from the first series on every refresh
const htmlgraphicsValue = htmlNode.getElementById('htmlgraphics-value');

if (htmlgraphicsValue) {
  const valueField = data.series[0]?.fields[1];
  if (valueField) {
    const length = valueField.values.length;
    htmlgraphicsValue.textContent = valueField.values.get(length - 1);
  } else {
    htmlgraphicsValue.textContent = "No data"
  }
}

options.rootCSS:
body {
  background: linear-gradient(135deg, #01292f, #000d12, #001b02);
  background-size: 400% 400%;
  animation: gradientBG 15s ease infinite;
  font-family: Arial, sans-serif;

}

@keyframes gradientBG {
  0% {
    background-position: 0% 50%;
  }
  50% {
    background-position: 100% 50%;
  }
  100% {
    background-position: 0% 50%;
  }
}

