  }
}

options.onRender:
(() => {
  if (!htmlNode || !data || !data.series) return;

  //uptime
  const getLastValue = (aliasOrRefId) => {
  const serie = data.series.find(s => s.name === aliasOrRefId || s.refId === aliasOrRefId);
  if (!serie) return null;
  const field = serie.fields.find(f => f.type === 'number' && f.values?.length);
  if (!field) return null;
  return field.values.get(field.values.length - 1);
};

const formatUptime = (seconds) => {
  if (!isFinite(seconds) || seconds < 0) return 'N/D';

  const d = Math.floor(seconds / 86400);
  const h = Math.floor((seconds % 86400) / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = Math.floor(seconds % 60);

  const parts = [];
  if (d > 0) parts.push(`${d}d`);
  if (h > 0 || d > 0) parts.push(`${h}h`);
  if (m > 0 || h > 0 || d > 0) parts.push(`${m}m`);
  parts.push(`${s}s`);

  return parts.join(' ');
};
// fim uptime

  // ---------- helpers ----------
  const findSeries = ({ alias, refId }) =>
    alias ? data.series.find(s => s.name === alias) || null
          : data.series.find(s => s.refId === refId) || null;

  // TEXT: prioriza string; senão, qualquer campo não-number e não-time; por fim, não "time"
const getString = ({ refId, alias, fieldName }) => {
  const s = findSeries({ refId, alias });

  if (s && fieldName) {
    const f = s.fields.find(ff => ff.name === fieldName && ff.values?.length);
    if (f) {
      const v = f.values.get(f.values.length - 1);
      return (v === undefined || v === null || v === '') ? null : String(v);
    }
  }

  for (const serie of data.series) {
    const f = serie.fields.find(ff => ff.name === fieldName && ff.values?.length);
    if (f) {
      const v = f.values.get(f.values.length - 1);
      return (v === undefined || v === null || v === '') ? null : String(v);
    }
  }

  return null;

};



  // MÉTRICA: somente campo number
  const getNumber = ({ alias, refId }) => {
    const s = findSeries({ alias, refId });
    if (!s) return null;
    const f = s.fields.find(ff => ff.type === 'number' && ff.values?.length);
    if (!f) return null;
    const v = f.values.get(f.values.length - 1);
    return (typeof v === 'number' && isFinite(v)) ? v : null;
  };

  const statusFromPing = (v) =>
    (typeof v === 'number' && isFinite(v) && v > 0 && v < 1000)
      ? { ok: true, text: 'ONLINE', color: '#34d399' }
      : { ok: false, text: 'OFFLINE', color: '#f87171' };

  // NOME DO BANNER

const banner = { banners: 'N' };
//const bannerT = getString({ banner: banner.banners, fieldName: 'Device name' }) ?? 'N/D';
//const bannerT = getString({ alias: 'N', fieldName: 'Device Name' }) ?? 'N/D';
const bannerT24 = { nameReff: 'N', typeReff: 'N' };
const bannerT = getString({ refId: bannerT24.nameReff, fieldName: 'Device Name' }) ?? 'N/D';

// UPTIME
const uptimeSec = Number(getLastValue('System uptime'));
const uptime = formatUptime(uptimeSec);

  // ---------- mapeamento ----------
  // 3F ADM2.4 GHz
  const q24  = { users: 'AP Usuarios 2G', ping: 'ICMP ping 2G' };
  const ref24 = { nameReff: 'J', typeReff: 'J' };

  // 5 GHz (NOME = C, TIPO = G)
  const q5   = { ssid: 'SSID 6GHz', users: '3AP Usuarios 5G', ping: 'ICMP ping 5G' };
  const ref5 = { nameRef: 'J', typeRef: 'J' }; // <- G é o TIPO 5G

    // VISITANTES6 GHz (NOME = C, TIPO = G)
  const q6   = { ssid: 'SSID 5GHz', users: 'AP Usuarios 6G', ping: 'ICMP ping 5G' };
  const ref6 = { name6: 'G', type6: 'G' }; // <- G é o TIPO 5G


  // ---------- coleta 2.4 ----------
  const ssid24  = ref24.ssidRef ? (getString({ refId: ref24.ssidRef }) ?? 'SSID 2.4GHz') : 'SSID 2.4GHz';

  const name24 = getString({ refId: ref24.nameReff, fieldName: 'SSID.2' }) ?? 'N/D';
  const type24 = getString({ refId: ref24.typeReff, fieldName: 'SSID.2.Tipo' }) ?? 'N/D';

  const users24 = getNumber({ alias: q24.users });
  const users24D = (typeof users24 === 'number' && isFinite(users24)) ? users24 : 'N/D';
  const ping24  = getNumber({ alias: q24.ping });
  const st24    = statusFromPing(ping24);

  // ---------- coleta 5 GHz ----------
  const ssid5  = getString({ alias: q5.ssid }) ?? 'SSID 5GHz';

  const name5 = getString({ refId: ref5.nameRef, fieldName: 'SSID.3' }) ?? 'N/D';
  const type5 = getString({ refId: ref5.typeRef, fieldName: 'SSID.3.TIPO' }) ?? 'N/D';

  const users5 = getNumber({ alias: q5.users });
  const users5D = (typeof users5 === 'number' && isFinite(users5)) ? users5 : 'N/D';
  const ping5  = getNumber({ alias: q5.ping });
  const st5    = statusFromPing(ping5);

  // ---------- VISITANTES coleta 6 GHz ----------
  const ssid6  = getString({ alias: q5.ssid }) ?? 'SSID 5GHz';

  const name6 = getString({ refId: ref6.name6, fieldName: 'SSID.1' }) ?? 'N/D';
  const type6 = getString({ refId: ref6.type6, fieldName: 'SSID.1.tipo' }) ?? 'N/D';

  const users6 = getNumber({ alias: q6.users });
  const users6D = (typeof users6 === 'number' && isFinite(users6)) ? users6 : 'N/D';
  const ping6  = getNumber({ alias: q6.ping });
  const st6    = statusFromPing(ping6);

  const cardPulseClass = (st24.ok && st5.ok) ? 'pulse-green' : 'pulse-red';

  const updatedAt = new Date().toLocaleString('pt-BR', {
    day:'2-digit', month:'2-digit', year:'numeric',
    hour:'2-digit', minute:'2-digit', second:'2-digit'
  });

  // ---------- HTML/CSS ----------
  htmlNode.innerHTML = `
    <style>
  @keyframes neonGreen {
    0%, 100% { box-shadow: 0 0 5px rgba(16,185,129,.7), 0 0 14px rgba(16,185,129,.35); }
    50% { box-shadow: 0 0 11px rgba(16,185,129,1), 0 0 20px rgba(16,185,129,.55); }
  }

  @keyframes neonRed {
    0%, 100% { box-shadow: 0 0 5px rgba(239,68,68,.7), 0 0 14px rgba(239,68,68,.35); }
    50% { box-shadow: 0 0 11px rgba(239,68,68,1), 0 0 20px rgba(239,68,68,.55); }
  }

  .updated-at {
    font-size: 6px;
    color: #6b7280;
    text-align: center;
    margin-top: 4px;
    font-style: italic;
    user-select: none;
  }

  .uptime {
    font-size: 7px;
    text-align: center;
    margin-top: 3px;
    color: #9ca3af;
  }

  .card-wrap {
    width: 280px;
    background: #030911;
    color: #e5e7eb;
    border-radius: 6px;
    padding: 8px;
    border: 1px solid transparent;
    font-family: Inter, system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
  }

  .pulse-green {
    border-color: #10b981;
    animation: neonGreen 1.6s infinite;
  }

  .pulse-red {
    border-color: #ef4444;
    animation: neonRed 1.4s infinite;
  }

  .banner {
    background: #2f3b4a;
    color: #e9f0f7;
    font-weight: 800;
    font-size: 18px;
    text-align: center;
    letter-spacing: 1px;
    padding: 5px 6px;
    border-radius: 4px;
    margin-bottom: 10px;
  }

  .pic {
    width: 82px;
    height: 82px;
    margin: 3px auto 4px;
    display: block;
    object-fit: contain;
    filter: drop-shadow(0 3px 5px rgba(0, 0, 0, .5));
  }

  .ssid {
    text-align: center;
    font-size: 10px;
    color: #e5e7eb;
    opacity: .95;
    font-weight: 800;
    margin: 5px 0;
    letter-spacing: 0.5px;
  }

  .table {
    background: #2c3645;
    border-radius: 10px;
    padding: 7px 9px;
    margin: 0 3px 6px;
  }

  .thead, .trow {
    display: grid;
    grid-template-columns: 1.2fr 1fr .9fr 1.1fr;
    column-gap: 9px;
    align-items: center;
    font-size: 9px;
  }

  .thead {
    color: #dbe5f0;
    font-weight: 800;
    letter-spacing: 0.5px;
    margin-bottom: 4px;
  }

  .trow {
    color: #c9d2dc;
    font-weight: 600;
  }

  .muted {
    color: #aeb7c2;
  }

  .status {
    font-weight: 800;
    letter-spacing: 0.5px;
  }

  .status.ok {
    color: #34d399;
  }

  .status.bad {
    color: #f87171;
  }
</style>

    <div class="card-wrap ${cardPulseClass}">
      <div class="banner">UNIFI ADM</div>
      <img class="pic" src="https://raw.githubusercontent.com/cyberconsecurity/Unifi/refs/heads/main/WiFi/PNG/U6-LR.png" alt="device" />

      <!-- 2.4 GHz -->
      <div class="ssid">${ssid24}</div>
      <div class="table">
        <div class="thead"><div>NOME</div><div>TIPO</div><div>USUÁRIOS</div><div>STATUS</div></div>
        <div class="trow">
          <div class="muted">${String(name24)}</div>
          <div class="muted">${String(type24)}</div>
          <div>${users24D}</div>
          <div class="status ${st24.ok ? 'ok' : 'bad'}">${st24.text}</div>
        </div>
      </div>

      <!-- 5 GHz -->
      <div class="ssid">${ssid5}</div>
      <div class="table">
        <div class="thead"><div>NOME</div><div>TIPO</div><div>USUÁRIOS</div><div>STATUS</div></div>
        <div class="trow">
          <div class="muted">${String(name5)}</div>
          <div class="muted">${String(type5)}</div>
          <div>${users5D}</div>
          <div class="status ${st5.ok ? 'ok' : 'bad'}">${st5.text}</div>
        </div>
      </div>

       <!-- VISITANTES GHz -->
      <div class="ssid">${ssid6}</div>
      <div class="table">
        <div class="thead"><div>NOME</div><div>TIPO</div><div>USUÁRIOS</div><div>STATUS</div></div>
        <div class="trow">
          <div class="muted">${String(name6)}</div>
          <div class="muted">${String(type6)}</div>
          <div>${users6D}</div>
          <div class="status ${st6.ok ? 'ok' : 'bad'}">${st6.text}</div>
        </div>
      </div>

      <div class="updated-at">Atualizado às ${updatedAt}</div>
      <div class="uptime">Uptime: ${uptime}</div>
    </div>
  `;
})();

